import React, { useState, useEffect } from "react";
import {
    SectionWrapper,
    Wrapper,
} from "../../components/Styles/RegisterStyles.js";
import axios from "axios";
import DataTable from "react-data-table-component";
import { Link } from "react-router-dom";
import { FaEye, FaEllipsisV } from "react-icons/fa";
import SideBar from '../../components/Investor/social/SideBar.jsx';
import TopBar from '../../components/Investor/social/TopBar.jsx';
import { DataRoomSection } from "../../components/Styles/DataRoomStyle.js";
import { useNavigate } from 'react-router-dom';
import CapitalRoundViewCompanyInvite from "../../components/Investor/popup/CapitalRoundViewCompanyInvite.jsx"
import ChatMessageModal from "../../components/social/company/ChatMessageModal.jsx";
import DangerAlertPopup from "../../components/Admin/DangerAlertPopup.jsx";
import { API_BASE_URL } from "../../config/config.js";

function DiscoverCompanyList() {
    const navigate = useNavigate();
    const [popupOpen, setPopupOpen] = useState(false);
    const [selectedIds, setSelectedIds] = useState({ id: null, roundrecord_id: null });
    const [open, setOpen] = useState(false);
    const [messagesuccessError, setmessagesuccessError] = useState("");
    const [errr, seterrr] = useState(false);
    const [records, setRecords] = useState([]);
    const [ClientIP, setClientIP] = useState("");
    const [CountryName, setCountryName] = useState("");

    // ✅ Filter tab state
    const [activeFilter, setActiveFilter] = useState("all"); // "all" | "interested" | "not_interested"

    const customStyles = {
        table: {
            style: {
                overflow: "visible !important",
                minWidth: "100%",
                boxShadow: "0px 3px 12px rgb(0 0 0 / 16%)",
                borderRadius: "12px",
            },
        },
        headCells: {
            style: {
                backgroundColor: "#efefef !important",
                fontWeight: "600",
                fontSize: "0.9rem",
                color: "#000 !important",
                whiteSpace: "nowrap",
            },
        },
        cells: {
            style: {
                whiteSpace: "nowrap",
                textOverflow: "ellipsis",
                backgroundColor: "#fff !important",
            },
        },
        rows: {
            style: {
                fontSize: "0.8rem",
                fontWeight: "500",
                "&:hover": { backgroundColor: "#e8f0fe" },
            },
            stripedStyle: { backgroundColor: "#f4f6f8" },
        },
        pagination: {
            style: { backgroundColor: "#fafafa", padding: "12px 16px" },
        },
    };

    var apiURL = API_BASE_URL + "api/user/investor/";

    const storedUsername = localStorage.getItem("InvestorData");
    const userLogin = JSON.parse(storedUsername);
    const access_token = userLogin?.access_token;
    const [searchText, setSearchText] = useState("");
    const [isCollapsed, setIsCollapsed] = useState(false);

    document.title = "Discover Company List - Investor";

    useEffect(() => {
        const getIP = async () => {
            try {
                const res = await fetch("https://ipapi.co/json/");
                const data = await res.json();
                setClientIP(data.ip);
                setCountryName(data.country_name);
            } catch (error) {
                console.error("Failed to fetch IP", error);
            }
        };
        getIP();
    }, []);

    useEffect(() => {
        getDiscoverCompanyList();
    }, []);

    const getDiscoverCompanyList = async () => {
        let formData = { investor_id: userLogin.id };
        try {
            const res = await axios.post(apiURL + "getDiscoverCompanyList", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                    'Authorization': `Bearer ${access_token}`,
                },
            });
            setRecords(res.data.results);
        } catch (err) { }
    };

    // ✅ Filter counts for badges
    const interestedCount = records?.filter(r => r.is_interested == 1).length || 0;
    const notInterestedCount = records?.filter(r => !r.is_interested || r.is_interested == 0).length || 0;

    const filteredData = records?.filter((item) => {
        // ✅ Tab filter
        if (activeFilter === "interested" && !item.is_interested) return false;
        if (activeFilter === "not_interested" && item.is_interested) return false;

        // ✅ Search filter
        const search = searchText.toLowerCase();
        if (!search) return true;

        const combinedFields = [
            item.company_name, item.company_city, item.company_state,
            item.company_country, item.company_postal_code, item.company_email,
            item.company_industory, item.year_registration, item.company_website,
            item.employee_number, item.gross_revenue, item.descriptionStep4,
            item.problemStep4, item.solutionStep4, item.nameOfRound,
            item.entity_type, item.entity_name, item.business_number,
            item.jurisdiction_country, item.entity_structure,
            item.office_address, item.mailing_address, item.articles,
        ]
            .filter(field => field !== null && field !== undefined)
            .map(field => String(field).toLowerCase())
            .join(" ");

        return combinedFields.includes(search);
    }) || [];

    // Chat
    const [selectedChatUser, setSelectedChatUser] = useState(null);
    const [showChatModal, setShowChatModal] = useState(false);
    var invname = userLogin?.first_name + " " + userLogin?.last_name;
    const currentUser = {
        id: userLogin.id,
        type: "investor",
        name: invname,
        email: userLogin.email,
    };

    const handlemessage = (corpid, name, email, logo) => {
        setSelectedChatUser({ id: corpid, type: "company", name, role: "Company", avatar: logo });
        setShowChatModal(true);
    };

    const handleopenPopup = (id, roundrecord_id) => {
        setSelectedIds({ company_id: id, roundrecord_id });
        setPopupOpen(true);
    };

    function formatCurrentDate(input) {
        const date = new Date(input);
        if (isNaN(date)) return "";
        const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun", "Jul", "Aug", "Sep", "Oct", "Nov", "Dec"];
        const day = date.getDate();
        const month = months[date.getMonth()];
        const year = date.getFullYear();
        const getOrdinal = (n) => {
            if (n >= 11 && n <= 13) return "th";
            switch (n % 10) {
                case 1: return "st";
                case 2: return "nd";
                case 3: return "rd";
                default: return "th";
            }
        };
        return `${month} ${day}${getOrdinal(day)}, ${year}`;
    }

    const handleInterested = async (companyId) => {
        setRecords(prev =>
            prev.map(row =>
                row.id === companyId ? { ...row, is_interested: !row.is_interested } : row
            )
        );

        let formData = { investor_id: userLogin.id, company_id: companyId };

        try {
            const res = await axios.post(apiURL + "interestedCompany", formData, {
                headers: {
                    Accept: "application/json",
                    "Content-Type": "application/json",
                    'Authorization': `Bearer ${access_token}`,
                },
            });

            if (res.data.status === 1) {
                seterrr(false);
                setmessagesuccessError(
                    res.data.action === "added"
                        ? "Company marked as interested successfully!"
                        : "Interest removed successfully!"
                );
            } else {
                setRecords(prev =>
                    prev.map(row =>
                        row.id === companyId ? { ...row, is_interested: !row.is_interested } : row
                    )
                );
                seterrr(true);
                setmessagesuccessError("Something went wrong. Please try again.");
            }
        } catch (err) {
            setRecords(prev =>
                prev.map(row =>
                    row.id === companyId ? { ...row, is_interested: !row.is_interested } : row
                )
            );
            seterrr(true);
            setmessagesuccessError("Something went wrong. Please try again.");
        }

        setTimeout(() => setmessagesuccessError(""), 3000);
    };

    // ✅ Tab button style helper
    const tabStyle = (key) => ({
        padding: "7px 16px",
        borderRadius: 20,
        border: "none",
        cursor: "pointer",
        fontSize: "13px",
        fontWeight: 600,
        background: activeFilter === key ? "#CC0000" : "#f3f4f6",
        color: activeFilter === key ? "#fff" : "#6b7280",
        transition: "all 0.15s",
        display: "flex",
        alignItems: "center",
        gap: 6,
    });

    const badgeStyle = (key) => ({
        background: activeFilter === key ? "rgba(255,255,255,0.3)" : "#e5e7eb",
        color: activeFilter === key ? "#fff" : "#6b7280",
        borderRadius: 20,
        padding: "1px 7px",
        fontSize: 11,
        fontWeight: 700,
    });

    return (
        <>
            <main>
                <div className='d-flex align-items-start gap-0'>
                    <SideBar />
                    <div className='d-flex flex-grow-1 flex-column gap-0'>
                        <TopBar />
                        <SectionWrapper className="d-block p-md-4 p-3">
                            <div className="container-fluid">
                                <DataRoomSection className="d-flex flex-column gap-3">
                                    <div className="titleroom flex-wrap gap-3 d-flex justify-content-between align-items-center border-bottom pb-3">
                                        <h4 className="mainh1">Discover Company List</h4>
                                    </div>

                                    {/* Success/Error message */}
                                    {messagesuccessError && (
                                        <div className={`flex items-center justify-between gap-3 shadow-lg ${errr ? "error_pop" : "success_pop"}`}>
                                            <div className="d-flex align-items-center gap-2">
                                                <span className="d-block">{messagesuccessError}</span>
                                            </div>
                                            <button type="button" className="close_btnCros" onClick={() => setmessagesuccessError("")}>×</button>
                                        </div>
                                    )}

                                    {/* ✅ Filter Tabs + Search */}
                                    <div className="d-flex justify-content-between align-items-center flex-wrap gap-2">
                                        {/* Tabs */}
                                        <div style={{ display: "flex", gap: 8 }}>
                                            <button
                                                style={tabStyle("all")}
                                                onClick={() => setActiveFilter("all")}
                                            >
                                                All
                                                <span style={badgeStyle("all")}>{records?.length || 0}</span>
                                            </button>
                                            <button
                                                style={tabStyle("interested")}
                                                onClick={() => setActiveFilter("interested")}
                                            >
                                                {/* Heart icon */}
                                                <svg width="13" height="13" viewBox="0 0 24 24" fill={activeFilter === "interested" ? "currentColor" : "none"} stroke="currentColor" strokeWidth="2">
                                                    <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
                                                </svg>
                                                Interested
                                                <span style={badgeStyle("interested")}>{interestedCount}</span>
                                            </button>
                                            <button
                                                style={tabStyle("not_interested")}
                                                onClick={() => setActiveFilter("not_interested")}
                                            >
                                                Not Interested
                                                <span style={badgeStyle("not_interested")}>{notInterestedCount}</span>
                                            </button>
                                        </div>

                                        {/* Search */}
                                        <input
                                            type="search"
                                            placeholder="Search Here..."
                                            className="textarea_input"
                                            value={searchText}
                                            onChange={(e) => setSearchText(e.target.value)}
                                            style={{ padding: "10px", width: "100%", maxWidth: "200px", fontSize: "14px" }}
                                        />
                                    </div>

                                    <div className="d-flex flex-column justify-content-between align-items-start tb-box">
                                        <DataTable
                                            customStyles={customStyles}
                                            columns={[
                                                {
                                                    name: "Company Name",
                                                    selector: (row) => row.company_name,
                                                    sortable: true,
                                                    cell: (row) => <span>{row.company_name}</span>,
                                                },
                                                {
                                                    name: "Location",
                                                    selector: (row) => row.company_city,
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <span>
                                                            {[row.company_city, row.company_state, row.company_country, row.company_postal_code]
                                                                .filter(Boolean).join(", ") || "—"}
                                                        </span>
                                                    ),
                                                },
                                                {
                                                    name: "Date of Incorporation",
                                                    selector: (row) => formatCurrentDate(row.year_registration),
                                                    sortable: true,
                                                    cell: (row) => <span>{formatCurrentDate(row.year_registration)}</span>,
                                                },
                                                {
                                                    name: "Company Overview",
                                                    sortable: true,
                                                    cell: (row) => (
                                                        <Link
                                                            title="View Company Detail"
                                                            to={`/investor/company-discover-view/${row.id}`}
                                                            target="_blank"
                                                            className="dropdown-item"
                                                            style={{ display: "flex", alignItems: "center", padding: "8px 16px", color: "#333", textDecoration: "none" }}
                                                        >
                                                            <FaEye style={{ cursor: "pointer", color: "#CC0000" }} />
                                                        </Link>
                                                    ),
                                                },
                                                {
                                                    name: "Actions",
                                                    cell: (row) => (
                                                        <div className="d-flex align-items-center gap-2">
                                                            <button
                                                                onClick={() => handleInterested(row.id)}
                                                                style={{
                                                                    backgroundColor: row.is_interested ? '#22c55e' : '#6c757d',
                                                                    color: 'white', border: 'none', borderRadius: '6px',
                                                                    padding: '6px 12px', fontSize: '13px', fontWeight: '500',
                                                                    cursor: 'pointer', display: 'flex', alignItems: 'center',
                                                                    gap: '5px', whiteSpace: 'nowrap', transition: 'background 0.2s',
                                                                }}
                                                                onMouseEnter={(e) => e.currentTarget.style.backgroundColor = row.is_interested ? '#16a34a' : '#5a6268'}
                                                                onMouseLeave={(e) => e.currentTarget.style.backgroundColor = row.is_interested ? '#22c55e' : '#6c757d'}
                                                            >
                                                                {row.is_interested ? (
                                                                    <>
                                                                        <svg width="13" height="13" viewBox="0 0 24 24" fill="currentColor" stroke="currentColor" strokeWidth="2">
                                                                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
                                                                        </svg>
                                                                        Interested
                                                                    </>
                                                                ) : (
                                                                    <>
                                                                        <svg width="13" height="13" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                                                                            <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z" />
                                                                        </svg>
                                                                        Mark Interested
                                                                    </>
                                                                )}
                                                            </button>
                                                        </div>
                                                    ),
                                                    ignoreRowClick: true,
                                                    allowOverflow: true,
                                                    minWidth: '180px',
                                                },
                                            ]}
                                            className="datatb-report"
                                            data={filteredData}
                                            pagination
                                            highlightOnHover
                                            striped
                                            responsive
                                            paginationRowsPerPageOptions={[10, 25, 50, 100]}
                                            paginationComponentOptions={{
                                                rowsPerPageText: "Rows per page:",
                                                rangeSeparatorText: "of",
                                                noRowsPerPage: false,
                                                selectAllRowsItem: false,
                                            }}
                                        />
                                    </div>
                                </DataRoomSection>
                            </div>
                        </SectionWrapper>
                    </div>
                </div>
            </main>

            {showChatModal && selectedChatUser && (
                <ChatMessageModal
                    onClose={() => { setShowChatModal(false); setSelectedChatUser(null); }}
                    currentUser={currentUser}
                    selectedUser={selectedChatUser}
                />
            )}
            {popupOpen && (
                <CapitalRoundViewCompanyInvite
                    id={selectedIds.id}
                    roundrecord_id={selectedIds.roundrecord_id}
                    onClose={() => setPopupOpen(false)}
                />
            )}
        </>
    );
}

export default DiscoverCompanyList;